      { icone: "🫐", titre: "Acaí préparé", detail: "CRUCIAL : utiliser de la PURÉE D'AÇAÍ CONGELÉE (marques Sambazon, Loja Açaí). Sortir 5 min avant pour faciliter le mix. À défaut : poudre d'açaí (moins authentique mais OK).", badge: "⏱ 5 min" },
      { icone: "🍌", titre: "Bananes congelées", detail: "SECRET BRÉSILIEN : utiliser des BANANES CONGELÉES (peler, trancher, congeler 4h+). Donne la texture milkshake DENSE sans avoir besoin de glaçons.", badge: "⏱ -" },
      { icone: "🌀", titre: "Mixer la base", detail: "Dans un blender PUISSANT : açaí (200g congelé) + 2 bananes congelées en rondelles + 100ml de lait d'amande + 1 cc de sirop d'érable. Mixer 30-45 sec jusqu'à texture SORBET épais.", badge: "⏱ 45 sec" },
      { icone: "✨", titre: "Texture idéale", detail: "Doit être ÉPAIS comme un sorbet (la cuillère doit tenir debout dans le bowl). Si trop liquide : ajouter banane congelée. Si trop dur : ajouter un peu de lait.", badge: "⏱ 30 sec" },
      { icone: "🥣", titre: "Service esthétique", detail: "Verser dans des bols larges (visuel important !). Lisser le dessus à la maryse.", badge: "⏱ 1 min" },
      { icone: "🍓", titre: "Toppings — l'art du açaí", detail: "DISPOSITION ARTISTIQUE : disposer les toppings en SECTIONS DISTINCTES par couleur (style Instagram). Au choix : tranches de banane, framboises, myrtilles, fraises, kiwi, mangue.", badge: "⏱ 3 min" },
      { icone: "🌰", titre: "Croquant", detail: "Saupoudrer : granola maison ou bio, noix concassées (amandes effilées, noix de pécan), graines (chia, lin, courge, tournesol).", badge: "⏱ 1 min" },
      { icone: "🥥", titre: "Touches gourmandes", detail: "Drizzle généreux de : beurre d'amande ou sirop d'érable, flocons de noix de coco. Option : pollen de fleurs pour bonus santé.", badge: "⏱ 1 min" },
      { icone: "🌿", titre: "Final", detail: "Une feuille de menthe pour la décoration. Servir IMMÉDIATEMENT (sinon ça fond). Manger à la cuillère, en piochant un peu de tout à chaque bouchée. Énergie pour la journée !", badge: null }
