      { icone: "🔥", titre: "Préchauffer le four", detail: "Préchauffer le four à 200 °C. Beurrer un moule à tarte. Minimum 10 min à la bonne température pour un démarrage de cuisson correct.", badge: null },
      { icone: "🥧", titre: "Foncer le moule", detail: "Étaler la pâte brisée dans le moule. Piquer le fond avec une fourchette. Mettre au réfrigérateur le temps de préparer les pommes.", badge: "⏱ 20 min au frais" },
      { icone: "🍎", titre: "Préparer la compote", detail: "Éplucher et couper 3 pommes en morceaux. Les cuire à feu doux avec le beurre, 50 g de sucre, le jus de citron et l'eau jusqu'à obtenir une compote. Écraser grossièrement. ASTUCE CHEF : couteau bien aiguisé pour des coupes nettes.", badge: "⏱ 10–15 min" },
      { icone: "🔪", titre: "Préparer les pommes du dessus", detail: "Éplucher les 3 pommes restantes, les couper en fines lamelles régulières d'environ 3 mm. Arroser d'un peu de jus de citron pour éviter l'oxydation. ASTUCE CHEF : couteau bien aiguisé pour des coupes nettes.", badge: null },
      { icone: "🏗️", titre: "Monter la tarte", detail: "Étaler la compote sur le fond de tarte. Disposer les lamelles de pommes en rosace ou en éventail par-dessus, en les faisant se chevaucher légèrement.", badge: null },
      { icone: "🍬", titre: "Sucrer et enfourner", detail: "Saupoudrer de 2 c. à soupe de sucre (et éventuellement de cannelle). Enfourner à 200 °C. Chaleur tournante pour une cuisson uniforme.", badge: "⏱ 30–35 min" },
      { icone: "🍑", titre: "Nappage abricot", detail: "Sortir la tarte du four. Faire chauffer la confiture d'abricot avec un peu d'eau et badigeonner la tarte encore chaude pour la faire briller.", badge: null },
      { icone: "❄️", titre: "Servir", detail: "Laisser tiédir avant de servir. Délicieuse tiède avec une boule de glace vanille ou de la crème fraîche !", badge: null }
