      { icone: "🥩", titre: "Préparer les keftas", detail: "Mélanger viande d'agneau hachée + oignon râpé + persil + coriandre + cumin + paprika + sel + poivre + 1 pincée de cannelle. ASTUCE CHEF : pétrir 3 min pour que les boulettes se tiennent.", badge: "⏱ 5 min" },
      { icone: "🎯", titre: "Former les boulettes", detail: "Façonner des petites boulettes de la taille d'une grosse cerise. Mouiller les mains pour éviter qu'elles collent. Réserver au frais 15 min pour qu'elles raffermissent.", badge: "⏱ 15 min" },
      { icone: "🍅", titre: "Sauce tomate", detail: "Dans un tajine ou cocotte : faire revenir oignons émincés dans l'huile d'olive 5 min. Ajouter tomates pelées concassées, 1 cuillère de concentré, ail haché, cumin, paprika, sucre, sel.", badge: "⏱ 10 min" },
      { icone: "⏳", titre: "Mijoter la sauce", detail: "Cuire 15 min à feu doux jusqu'à épaississement. La sauce doit napper la cuillère. Ajouter un peu d'eau si elle réduit trop.", badge: "⏱ 15 min" },
      { icone: "🥩", titre: "Pocher les keftas", detail: "Plonger délicatement les boulettes dans la sauce. NE PAS REMUER tout de suite pour ne pas les casser. Cuire 8-10 min en couvrant.", badge: "⏱ 10 min" },
      { icone: "🥚", titre: "Casser les œufs", detail: "Hors du feu, casser les œufs directement dans la sauce entre les boulettes. Saler légèrement. Remettre sur feu doux à couvert 5-6 min. Le blanc doit être pris mais le jaune coulant.", badge: "⏱ 6 min" },
      { icone: "🌿", titre: "Garniture", detail: "Parsemer généreusement de persil et coriandre fraîche ciselés. Ajouter un peu de cumin moulu et paprika.", badge: null },
      { icone: "🥖", titre: "Service", detail: "Servir BRÛLANT dans le tajine. On mange avec du pain frais (khobz) pour saucer. ASTUCE : un filet d'huile d'olive crue sur le dessus juste avant de servir.", badge: null }
