      { icone: "🍷", titre: "Pâte au Marsala", detail: "Mélanger farine + 1 cc cacao + 1 cc sucre + 1 pincée cannelle. Faire un puits, ajouter Marsala (vin sicilien) + 1 œuf + 1 cs saindoux ou beurre fondu + 1 pincée sel.", badge: "⏱ 5 min" },
      { icone: "✋", titre: "Pétrir", detail: "Pétrir 10 min jusqu'à pâte lisse et élastique. Forme une boule. Filmer et REPOSER 1h au frais. Pâte DOIT reposer !", badge: "⏱ 1h" },
      { icone: "🥄", titre: "Crème ricotta", detail: "ÉTAPE CRITIQUE : la ricotta DOIT s'égoutter au moins 4h (idéalement la veille) au frais dans une passoire avec linge. Sinon crème trop liquide !", badge: "⏱ 4h" },
      { icone: "🌿", titre: "Préparer garniture", detail: "Mélanger ricotta bien égouttée + sucre glace + 1 cc d'eau de fleur d'oranger + pépites de chocolat noir + pistaches concassées. Réserver au frais.", badge: "⏱ 5 min" },
      { icone: "🥖", titre: "Étaler très fin", detail: "Étaler la pâte au rouleau ou avec laminoir TRÈS FINE (1-2 mm). Découper des disques de 10 cm.", badge: "⏱ 10 min" },
      { icone: "🎯", titre: "Enrouler", detail: "Enrouler chaque disque autour d'un tube à cannoli (ou tube en inox de 2cm Ø). COLLER le bord avec un peu de blanc d'œuf battu. ASTUCE CHEF : appuyer fortement pour souder.", badge: null },
      { icone: "🍳", titre: "Frire", detail: "Chauffer huile à 180°C. Frire 2-3 cannoli (avec leur tube) à la fois. Cuire 2-3 min jusqu'à dorés ET cloqués (bulles c'est bon signe !). Égoutter, refroidir, démouler délicatement.", badge: "⏱ 3 min/fournée" },
      { icone: "✨", titre: "Garnir", detail: "ATTENTION : garnir SEULEMENT au moment de servir (sinon ramollit). Avec une poche à douille, garnir les 2 côtés. Tremper les extrémités dans pistaches concassées.", badge: null },
      { icone: "🍽️", titre: "Service", detail: "Saupoudrer de sucre glace. Servir IMMÉDIATEMENT. Accompagner d'un café espresso ou d'un Marsala. Buon appetito !", badge: null }
