      { icone: "⏳", titre: "1ère pousse", detail: "Couvrir d'un linge humide et laisser pousser à 25°C (four éteint avec lampe allumée) pendant 1h30. La pâte doit doubler.", badge: "⏱ 1h30" },
      { icone: "🥖", titre: "Façonner", detail: "Dégazer doucement. Former un pâton oblong ou rond sur plaque farinée. Faire des entailles décoratives au couteau bien aiguisé.", badge: "⏱ 5 min" },
      { icone: "⏳", titre: "2ème pousse", detail: "Laisser repousser 30 min. Pendant ce temps : préchauffer le four à 240°C avec une plaque vide en bas.", badge: "⏱ 30 min" },
      { icone: "💨", titre: "Cuisson au four", detail: "ASTUCE CHEF : enfourner, verser 200 ml d'eau bouillante dans la plaque du bas (vapeur = croûte croustillante). Cuire 15 min à 240°C, puis 30 min à 200°C.", badge: "⏱ 45 min" },
      { icone: "🎵", titre: "Tester la cuisson", detail: "Tapoter le dessous du pain : son creux = c'est cuit. Sinon, 5-10 min de plus. Laisser refroidir COMPLÈTEMENT sur grille (au moins 1h) avant de trancher.", badge: "⏱ 1h" }
