      { icone: "🌾", titre: "Autolyse", detail: "ÉTAPE PRO : mélanger juste les farines (T80 + seigle) avec 320ml d'eau, sans levure ni sel. Couvrir et laisser reposer 30 min. La pâte va se développer toute seule. ASTUCE CHEF : améliore énormément la mie.", badge: "⏱ 30 min" },
      { icone: "🧪", titre: "Levain et levure", detail: "Dissoudre la levure dans 20ml d'eau tiède. Ajouter au mélange précédent avec le levain (si vous en avez) et le sel.", badge: null },
      { icone: "✋", titre: "Pétrissage", detail: "Pétrir 10 min au robot ou 15 min à la main. La pâte doit être souple, élastique, légèrement collante. ASTUCE : test de la fenêtre — étirer la pâte, doit former un voile sans déchirer.", badge: "⏱ 15 min" },
      { icone: "⏳", titre: "Pointage", detail: "Première levée : couvrir et laisser pousser 1h30 à 25°C jusqu'à doublement.", badge: "⏱ 1h30" },
      { icone: "✋", titre: "Rabats", detail: "ASTUCE PRO : pendant les 1h30, faire 2 rabats (replier la pâte sur elle-même) à 30 min d'intervalle. Donne du corps à la pâte.", badge: "⏱ 2x 1 min" },
      { icone: "🥖", titre: "Façonnage", detail: "Verser la pâte sur le plan fariné. Plier en 3 puis en 3 (lettre). Bouler. Mettre dans un banneton fariné, couture vers le HAUT.", badge: "⏱ 5 min" },
      { icone: "⏳", titre: "Apprêt", detail: "Deuxième levée 1h dans le banneton, couvert d'un linge. Pendant ce temps : préchauffer le four à 250°C avec une cocotte en fonte dedans.", badge: "⏱ 1h" },
      { icone: "🔥", titre: "Cuisson en cocotte", detail: "SECRET BOULANGER : retourner la pâte dans la cocotte ULTRA-CHAUDE. Faire des entailles. Couvrir et cuire 20 min à 250°C, puis 25 min sans couvercle à 230°C. Croûte parfaite garantie.", badge: "⏱ 45 min" },
      { icone: "🎵", titre: "Refroidir", detail: "Laisser refroidir SUR GRILLE au moins 1h avant de trancher. La mie continue de cuire en refroidissant.", badge: "⏱ 1h" }
