    ingredients: {},
    etapes: [
      { icone: "🥣", titre: "Génoise au cacao", detail: "Fouetter œufs ENTIERS + sucre au bain-marie jusqu'à 40°C en fouettant constamment. Retirer, continuer 10 min jusqu'à RUBAN épais et blanchi (triple de volume).", badge: "⏱ 15 min" },
      { icone: "🥄", titre: "Incorporer farine", detail: "Tamiser farine + cacao + 1 pincée de sel. Incorporer DÉLICATEMENT à la maryse, en soulevant. ASTUCE CHEF : ne pas casser l'air ! Ajouter beurre fondu tiède en filet.", badge: "⏱ 5 min" },
      { icone: "🔥", titre: "Cuire la génoise", detail: "Verser dans moule de 22 cm beurré et fariné. Cuire à 180°C 25-30 min. Test cure-dent. Démouler aussitôt, refroidir sur grille.", badge: "⏱ 30 min" },
      { icone: "🍒", titre: "Préparer les cerises", detail: "Si bocal : égoutter en gardant le jus. Si frais : dénoyauter et faire compoter 5 min avec 1 cs sucre. Réserver une dizaine entières pour décor.", badge: "⏱ 10 min" },
      { icone: "🍷", titre: "Sirop kirsch", detail: "Mélanger 100ml de jus de cerises + 3 cs kirsch + 1 cs sucre. Réserver. SECRET : ce sirop imbibe la génoise.", badge: null },
      { icone: "🍫", titre: "Copeaux chocolat", detail: "Avec un économe, raboter 200g de chocolat noir froid pour faire des copeaux. Réserver au frais.", badge: "⏱ 5 min" },
      { icone: "✂️", titre: "Trancher génoise", detail: "Une fois COMPLÈTEMENT REFROIDIE, couper la génoise en 3 disques égaux à l'aide d'un couteau-scie et d'un guide.", badge: "⏱ 5 min" },
      { icone: "🥛", titre: "Chantilly", detail: "Monter la crème TRÈS FROIDE en chantilly avec sucre glace. ASTUCE CHEF : crème, fouet et bol au frais 30 min avant. Ferme mais pas grainée.", badge: "⏱ 5 min" },
      { icone: "🏗️", titre: "Montage", detail: "1) Disque 1 + imbiber au sirop kirsch + couche chantilly + cerises hachées. 2) Disque 2 + sirop + chantilly + cerises. 3) Disque 3 + sirop. Couvrir TOUT le gâteau de chantilly.", badge: "⏱ 15 min" },
      { icone: "✨", titre: "Décor", detail: "Plaquer les copeaux de chocolat sur les côtés et le dessus. Poches à douille pour faire des rosaces de chantilly sur le dessus. Surmonter chaque rosace d'une cerise entière.", badge: "⏱ 10 min" },
      { icone: "❄️", titre: "Refroidir", detail: "RÉFRIGÉRER MINIMUM 4H avant de servir. La forêt-noire est meilleure le LENDEMAIN (les arômes se développent). Servir tranchée au couteau humidifié.", badge: "⏱ 4h" }
    ]
