      { icone: "🌿", titre: "Préparer poireaux", detail: "Trancher 3 poireaux dans la longueur. Bien LAVER pour enlever toute terre cachée dans les feuilles. Émincer finement (blanc + vert tendre).", badge: "⏱ 8 min" },
      { icone: "🍳", titre: "Fondue poireaux", detail: "Dans une grande poêle, faire fondre 30g de beurre. Ajouter poireaux + 2 cs d'eau + sel + poivre. CUIRE À COUVERT à FEU DOUX 20 min en remuant. Doivent fondre sans colorer. ASTUCE CHEF : c'est la base !", badge: "⏱ 20 min" },
      { icone: "🥓", titre: "Lardons", detail: "Faire revenir les lardons à sec dans une autre poêle 5 min jusqu'à dorés mais pas secs. Égoutter sur papier absorbant.", badge: "⏱ 5 min" },
      { icone: "🥚", titre: "Appareil", detail: "Battre 3 œufs + 20cl de crème fraîche + 10cl de lait + sel + poivre + muscade râpée généreusement. NE PAS TROP SALER (les lardons salent déjà).", badge: "⏱ 3 min" },
      { icone: "🥧", titre: "Précuisson", detail: "Cuire à blanc la pâte 10 min à 180°C avec papier sulfurisé + haricots secs (anti-bombe). Retirer les haricots, encore 5 min. ASTUCE CHEF : empêche que la quiche soit détrempée.", badge: "⏱ 15 min" },
      { icone: "🏗️", titre: "Montage", detail: "Étaler la fondue de poireaux sur le fond précuit. Parsemer les lardons. Verser l'appareil œufs-crème. Parsemer de fromage râpé (gruyère ou comté).", badge: "⏱ 5 min" },
      { icone: "🔥", titre: "Cuisson finale", detail: "Cuire à 180°C chaleur tournante 30-35 min. La quiche doit être DORÉE et BOMBÉE. Doit légèrement trembloter au centre.", badge: "⏱ 35 min" },
      { icone: "🍽️", titre: "Service", detail: "Laisser tiédir 5 min avant de couper (sinon trop liquide). Servir tiède avec une salade verte vinaigrette. Vin : Riesling ou Chablis.", badge: null }
