    etapes: [
      { icone: "🥔", titre: "Couper en cubes parfaits", detail: "Éplucher les pommes de terre (Bintje ou Agria). Couper en cubes IRRÉGULIERS de 2-3cm. ASTUCE CHEF : pas trop réguliers — c'est l'esthétique rustique espagnole.", badge: "⏱ 10 min" },
      { icone: "💧", titre: "Première cuisson à l'eau", detail: "ASTUCE PRO : faire cuire les cubes 8-10 min dans une grande casserole d'eau salée. Doivent être presque cuits mais encore fermes. Égoutter et sécher au torchon (ESSENTIEL pour le croustillant).", badge: "⏱ 12 min" },
      { icone: "🍅", titre: "Sauce brava", detail: "Dans une casserole : 2 cs d'huile d'olive, ail haché, faire revenir 1 min. Ajouter tomates pelées concassées + paprika fumé (pimentón de la Vera) + 1 pincée de piment de Cayenne + 1 cc de vinaigre de Xérès + sel + sucre. Mijoter 15 min.", badge: "⏱ 15 min" },
      { icone: "🌶️", titre: "Mixer la sauce", detail: "SECRET DE LA BRAVA : mixer la sauce au mixeur plongeant pour une texture LISSE et BRILLANTE. Goûter et ajuster : doit être RELEVÉE (mais pas trop forte) et FUMÉE.", badge: "⏱ 3 min" },
      { icone: "🧄", titre: "Aioli rapide", detail: "Mélanger 4 cs de mayonnaise + 1 gousse d'ail PRESSÉE + 1 cc de jus de citron + 1 pincée de sel. Variante traditionnelle : émulsion maison à l'huile d'olive (plus long).", badge: "⏱ 3 min" },
      { icone: "🔥", titre: "Frire les pommes de terre", detail: "Dans une grande poêle avec 4 cs d'huile d'olive bien chaude (180°C), frire les cubes pré-cuits jusqu'à DORÉS et CROUSTILLANTS partout (10-12 min). Égoutter sur papier absorbant. Saler.", badge: "⏱ 12 min" },
      { icone: "🍽️", titre: "Dressage en tapas", detail: "Dans une petite poêle ou cazuela en terre : disposer les pommes de terre chaudes. NAPPER de sauce brava (pas tout, pour garder le croustillant). DRIZZLE d'aioli en quadrillage par-dessus.", badge: "⏱ 2 min" },
      { icone: "🌿", titre: "Service tapas", detail: "Saupoudrer de persil ciselé. Servir IMMÉDIATEMENT bien chaud avec des cure-dents (la tradition espagnole !) et un verre de vin rouge Tempranillo ou bière. Salud !", badge: null }
    ]
