      { icone: "🥩", titre: "Bouillon de bœuf", detail: "Dans un grand faitout : 500g de jarret de bœuf + 2L d'eau froide + 1 oignon + 1 carotte + 2 feuilles de laurier + grains de poivre. Porter à ébullition, écumer. Mijoter 1h30 à FEU TRÈS DOUX. ASTUCE CHEF : un bon bouillon de bœuf est la base.", badge: "⏱ 1h30" },
      { icone: "🟣", titre: "Préparer les betteraves", detail: "Éplucher 600g de betteraves cuites OU les cuire séparément (45 min à l'eau ou au four). Couper en BÂTONNETS (julienne). ASTUCE PRO : on garde les betteraves à part pour les ajouter en fin (préserve la couleur rouge vif).", badge: "⏱ 10 min" },
      { icone: "🥕", titre: "Légumes", detail: "Émincer 1 oignon, 2 carottes en bâtonnets, 2 pommes de terre en cubes. Émincer 1/4 de chou vert en lanières.", badge: "⏱ 10 min" },
      { icone: "🍅", titre: "Sofrito", detail: "Dans une grande sauteuse : faire revenir l'oignon dans 2 cs d'huile 5 min. Ajouter carottes + 2 tomates pelées concassées + 1 cs de concentré de tomate. Cuire 10 min à feu moyen jusqu'à confit.", badge: "⏱ 15 min" },
      { icone: "🍲", titre: "Assembler", detail: "Filtrer le bouillon. Retirer la viande, couper en cubes, réserver. Dans le bouillon : ajouter pommes de terre + sofrito. Cuire 10 min.", badge: "⏱ 12 min" },
      { icone: "🥬", titre: "Chou et betteraves", detail: "Ajouter chou émincé + betteraves en bâtonnets + 2 cs de vinaigre de vin + 1 cs de sucre. Le vinaigre fixe la couleur rouge !", badge: "⏱ 5 min" },
      { icone: "⏳", titre: "Mijoter ensemble", detail: "Mijoter 15 min à feu doux. Goûter et ajuster : sel, poivre, vinaigre, sucre. Le bortsch doit être ÉQUILIBRÉ sucré-acide-salé. Ajouter ail pressé en fin (3 gousses) et aneth.", badge: "⏱ 15 min" },
      { icone: "🥩", titre: "Remettre la viande", detail: "Réintégrer les cubes de bœuf cuit dans la soupe. Réchauffer 2 min. ASTUCE CHEF : viande TENDRE à fondre dans la bouche.", badge: "⏱ 2 min" },
      { icone: "🍶", titre: "Service russe", detail: "Servir BRÛLANT dans des bols larges. ESSENTIEL : 1 grosse cuillère de crème fraîche par bol + aneth ciselé frais. Pain de seigle russe à côté. Vodka glacée optionnelle. Priyatnogo appetita !", badge: null }
