    ingredients: {},
    etapes: [
      { icone: "🐟", titre: "Dessaler la morue", detail: "CRUCIAL : la morue salée doit être DESSALÉE 24-48H à l'eau froide, en changeant l'eau 3-4 fois. ASTUCE CHEF : sinon plat IMMANGEABLE. Le morceau doit goûter légèrement salé après dessalage. Alternative express : achetée déjà dessalée.", badge: "⏱ 24-48h" },
      { icone: "💧", titre: "Pocher la morue", detail: "Plonger la morue dans une casserole d'EAU FROIDE. Porter à frémissement (pas bouillir). Cuire 10 min. Sortir, retirer peau et arêtes, ÉMIETTER à la main en gros morceaux. ASTUCE PRO : c'est manuel pour respecter la texture.", badge: "⏱ 15 min" },
      { icone: "🥔", titre: "Pommes de terre paille", detail: "TECHNIQUE PORTUGAISE : éplucher les pommes de terre, couper en BÂTONNETS TRÈS FINS (julienne de 3mm). Rincer puis SÉCHER au torchon (essentiel pour le croustillant).", badge: "⏱ 15 min" },
      { icone: "🔥", titre: "Frire les pommes de terre", detail: "Dans une grande poêle profonde avec 200ml d'huile à 170°C, frire les pommes de terre paille en 2-3 fournées. Doivent être DORÉES et CROUSTILLANTES. Égoutter sur papier absorbant. Saler.", badge: "⏱ 12 min" },
      { icone: "🧅", titre: "Oignons confits", detail: "Dans une grande sauteuse, faire fondre 2 oignons émincés dans 4 cs d'huile d'olive à FEU DOUX 15 min. Ne PAS colorer — juste TRANSLUCIDES et fondants. Ajouter ail haché en fin.", badge: "⏱ 15 min" },
      { icone: "🥄", titre: "Mélange initial", detail: "Ajouter la morue émiettée aux oignons confits. Mélanger délicatement. Réchauffer 2 min.", badge: "⏱ 3 min" },
      { icone: "🍟", titre: "Incorporer pommes de terre", detail: "Verser les pommes de terre frites dans la sauteuse. Mélanger DÉLICATEMENT pour ne pas casser le croustillant.", badge: "⏱ 1 min" },
      { icone: "🥚", titre: "Œufs brouillés signature", detail: "SECRET DU BRÁS : battre 6 œufs avec sel/poivre. Verser dans la sauteuse hors du feu. REMUER DÉLICATEMENT pour que les œufs cuisent à la chaleur résiduelle SANS DURCIR. Doit rester CRÉMEUX et FILANT.", badge: "⏱ 3 min" },
      { icone: "🌿", titre: "Finitions", detail: "Saupoudrer abondamment de persil ciselé. Décorer avec olives noires entières (essentiel à la tradition portugaise) et œufs durs en quartiers (option).", badge: "⏱ 2 min" },
      { icone: "🍽️", titre: "Service lisboète", detail: "Servir IMMÉDIATEMENT dans le plat de service. Le bacalhau à brás se mange ENSEMBLE — pas en couches. Salade verte simple à côté. Vin vert portugais (vinho verde) frais. Bom appetite !", badge: null }
    ]
