    ingredients: {},
    etapes: [
      { icone: "🐟", titre: "Choisir les poissons", detail: "CRUCIAL : un mélange de POISSONS DE ROCHE — rascasse, vive, congre, grondin, saint-pierre, petits crabes. Le poissonnier vendra un 'mix soupe' (économique). 1.2kg pour 6 personnes. ASTUCE : ces poissons sont LAIDS mais font la meilleure soupe !", badge: "⏱ 5 min" },
      { icone: "🔪", titre: "Préparer les poissons", detail: "Vider, écailler, couper en GROS tronçons. Garder les têtes (riches en saveur). Laver à l'eau froide. Sécher. ASTUCE CHEF : demander au poissonnier de le faire, c'est moins fastidieux.", badge: "⏱ 10 min" },
      { icone: "🥕", titre: "Mirepoix", detail: "Émincer : 2 oignons, 1 carotte, 1 branche de céleri, 1 fenouil, 4 gousses d'ail écrasées. Couper 4 tomates en quartiers.", badge: "⏱ 10 min" },
      { icone: "🔥", titre: "Suer les légumes", detail: "Dans une grande marmite, chauffer 6 cs d'huile d'olive. Faire revenir les légumes 10 min sans colorer. Ils doivent être translucides et parfumés.", badge: "⏱ 10 min" },
      { icone: "🐟", titre: "Saisir les poissons", detail: "Ajouter TOUS les poissons aux légumes. Augmenter le feu. Faire revenir 5-6 min en remuant — les poissons doivent ÉCLATER pour libérer leurs saveurs. C'est LE secret.", badge: "⏱ 6 min" },
      { icone: "🍷", titre: "Vin et tomates", detail: "Mouiller avec 200ml de vin blanc sec. Laisser réduire 5 min (l'alcool s'évapore). Ajouter tomates + 1 cs concentré tomate + bouquet garni (thym, laurier, persil) + zeste d'orange (touche provençale).", badge: "⏱ 5 min" },
      { icone: "💧", titre: "Mouiller", detail: "Couvrir d'eau froide à hauteur (2L environ). Ajouter 1 cc gros sel + poivre + safran (en pistil idéalement, ou en poudre). Porter à frémissement.", badge: "⏱ 5 min" },
      { icone: "⏳", titre: "Mijoter", detail: "Cuire à FEU DOUX 45 min couvercle entrouvert. Les poissons doivent se défaire complètement. La soupe doit prendre une couleur orangée intense.", badge: "⏱ 45 min" },
      { icone: "🌊", titre: "Mixer puis filtrer", detail: "ÉTAPE TECHNIQUE : mixer GROSSIÈREMENT au mixeur plongeant (avec arêtes et tout). PUIS filtrer impérativement au tamis fin chinois en PRESSANT FORTEMENT avec un pilon pour extraire toute la pulpe. Jeter les arêtes.", badge: "⏱ 10 min" },
      { icone: "🌶️", titre: "La rouille — sauce signature", detail: "Pendant la cuisson : piler 4 gousses d'ail + 1 piment rouge + 1 pomme de terre cuite. Monter en mayonnaise en ajoutant 1 jaune d'œuf, sel, et 200ml d'huile d'olive en filet. Couleur orange-rouge intense. ASTUCE CHEF : 1 pincée de safran ou paprika fumé.", badge: "⏱ 10 min" },
      { icone: "🥖", titre: "Croûtons aillés", detail: "Trancher une baguette rassise en rondelles. Frotter à l'ail. Toaster au four 5 min à 200°C. Doit être TRÈS sec et doré.", badge: "⏱ 5 min" },
      { icone: "🍽️", titre: "Service marseillais", detail: "Servir BRÛLANT en assiettes creuses. Chaque convive : tartiner les croûtons de rouille, les déposer dans la soupe, saupoudrer GÉNÉREUSEMENT de gruyère râpé. Pastis en accompagnement. Bon appétit !", badge: null }
    ]
