    ingredients: {},
    etapes: [
      { icone: "🥬", titre: "Émincer le chou — étape clé", detail: "ÉTAPE FONDAMENTALE : chou vert ou chou blanc, RETIRER le cœur dur. Émincer TRÈS FINEMENT (2-3mm max). Compter 400g pour 4 personnes. C'est la base de l'okonomiyaki — ne pas hacher au robot (texture trop fine).", badge: "⏱ 15 min" },
      { icone: "🌾", titre: "Pâte de base", detail: "Dans un grand bol : 200g de farine + 1 cc levure chimique + 1 pincée de sel + 1 cc de dashi en poudre (booster umami, option) + 200ml d'eau ou bouillon dashi. Mélanger jusqu'à pâte LISSE.", badge: "⏱ 5 min" },
      { icone: "🥚", titre: "Ajouter œufs", detail: "Battre 4 œufs et les incorporer à la pâte. Bien mélanger.", badge: "⏱ 2 min" },
      { icone: "🥬", titre: "Mélanger avec le chou", detail: "Ajouter le chou émincé à la pâte. Mélanger ÉNERGIQUEMENT pour bien enrober (la pâte doit recouvrir tout le chou). On peut ajouter 1 oignon vert ciselé, 50g de bénidashi en poudre.", badge: "⏱ 3 min" },
      { icone: "🥩", titre: "Garnitures", detail: "TRADITIONNEL : tranches de lard ou poitrine de porc fumée, crevettes, calamars, fromage. ASTUCE CHEF : OKONOMI veut dire 'comme vous voulez' en japonais !", badge: "⏱ 3 min" },
      { icone: "🔥", titre: "Chauffer la plancha", detail: "Grande poêle ou plaque chauffante, à feu MOYEN avec 1 cs d'huile. C'est crucial qu'elle soit bien chaude AVANT de verser la pâte.", badge: "⏱ 3 min" },
      { icone: "🥞", titre: "Cuire 1ère face", detail: "Verser une bonne louche de pâte (épaisseur 2cm minimum). FORMER UN CERCLE de 15cm de diamètre. Disposer dessus les lardons (côté qui sera retourné). Cuire 6-7 min, le dessous doit être bien doré.", badge: "⏱ 7 min" },
      { icone: "🔄", titre: "Le RETOURNAGE — moment clé", detail: "TECHNIQUE PRO : utiliser 2 grandes spatules ou une assiette retournée. Retourner d'un coup ferme. Les lardons seront maintenant au-dessus. Appuyer légèrement avec la spatule.", badge: "⏱ 1 min" },
      { icone: "🔥", titre: "Cuire 2ème face", detail: "Cuire 6-7 min de l'autre côté. Le centre doit être cuit à cœur (pas de pâte crue). Tester avec un cure-dent : doit ressortir sec.", badge: "⏱ 7 min" },
      { icone: "✨", titre: "Sauces et garnitures finales", detail: "RITUEL JAPONAIS : SUR LE DESSUS — étaler généreusement de la SAUCE OKONOMI (sweet+savoury). Puis ZIGZAGS de mayonnaise japonaise (Kewpie). Saupoudrer de KATSUOBUSHI (flocons de bonite séchée — qui dansent à la chaleur !) + algues nori en lamelles + oignon vert ciselé.", badge: "⏱ 2 min" },
      { icone: "🍽️", titre: "Service izakaya", detail: "Servir IMMÉDIATEMENT, brûlant, dans une assiette plate. Couper en quartiers à table comme une pizza. Bière japonaise (Asahi, Sapporo) en accompagnement. Itadakimasu !", badge: null }
    ]
