    ingredients: {},
    etapes: [
      { icone: "🍄", titre: "Choisir la truffe", detail: "ASTUCE CHEF MAJEURE : truffe noire FRAÎCHE du Périgord ou d'Italie (Tuber Melanosporum) en saison (nov-mars). À défaut : truffe d'été (Tuber Aestivum, plus accessible) ou huile à la truffe de qualité. ÉVITER les arômes synthétiques chimiques.", badge: "⏱ -" },
      { icone: "🧽", titre: "Brosser la truffe", detail: "Brosser DÉLICATEMENT la truffe à sec avec une brosse à champignon. NE PAS LA LAVER (perd des arômes). Réserver au frais dans du papier absorbant.", badge: "⏱ 3 min" },
      { icone: "🍝", titre: "Pâtes fraîches", detail: "IDÉALEMENT : tagliatelles fraîches faites maison ou achetées chez un pastificio. À défaut : tagliatelles sèches de qualité (De Cecco, Rummo). Compter 100g par personne.", badge: "⏱ -" },
      { icone: "🥄", titre: "Râper le parmesan", detail: "Râper FRAÎCHEMENT 120g de Parmigiano Reggiano AOP 24 mois (jamais en sachet pré-râpé). Garder à part 30g pour le service final.", badge: "⏱ 3 min" },
      { icone: "💧", titre: "Cuire les pâtes", detail: "Grande casserole d'eau BOUILLANTE TRÈS SALÉE (10g/L). Cuire les tagliatelles AL DENTE — 1 min de moins que sur l'emballage. ASTUCE CHEF : garder 1 louche d'EAU DE CUISSON (l'or des pâtes).", badge: "⏱ 4 min" },
      { icone: "🧈", titre: "Beurre noisette", detail: "Pendant ce temps : dans une grande poêle, faire fondre 80g de beurre. Continuer jusqu'à coloration NOISETTE (couleur ambrée, odeur de noisette). NE PAS BRÛLER. Hors du feu.", badge: "⏱ 4 min" },
      { icone: "🧄", titre: "Parfum d'ail", detail: "Ajouter 1 gousse d'ail entière LÉGÈREMENT écrasée au beurre. Laisser infuser 1 min. RETIRER l'ail avant la suite (juste pour parfumer subtilement).", badge: "⏱ 1 min" },
      { icone: "🍝", titre: "Mariage des pâtes", detail: "Égoutter les tagliatelles AL DENTE. Les jeter dans la poêle avec le beurre. Ajouter une LOUCHE D'EAU DE CUISSON + le parmesan râpé. SAUTER 1 min à feu vif en mélangeant CONSTAMMENT pour créer une émulsion crémeuse.", badge: "⏱ 2 min" },
      { icone: "🧂", titre: "Assaisonner", detail: "Saler MODÉRÉMENT (le parmesan est salé). POIVRER GÉNÉREUSEMENT au moulin (poivre noir Sarawak idéal). Goûter.", badge: "⏱ 1 min" },
      { icone: "🍝", titre: "Dressage immédiat", detail: "Servir IMMÉDIATEMENT (les pâtes refroidissent vite). Répartir dans 4 ASSIETTES CHAUDES. Utiliser une pince ou fourchette pour faire des 'nids' élégants.", badge: "⏱ 1 min" },
      { icone: "🍄", titre: "Truffe — le moment magique", detail: "RITUEL ITALIEN : à TABLE, devant les invités, RÂPER la truffe noire à la mandoline ou râpe spéciale truffe AU-DESSUS DE CHAQUE ASSIETTE. La chaleur libère les arômes. 1-2g par personne suffisent.", badge: "⏱ 1 min" },
      { icone: "🍷", titre: "Service", detail: "Saupoudrer de quelques copeaux de parmesan supplémentaires. Vin : Barolo, Brunello di Montalcino, Pinot Noir. Pain blanc pour saucer. Buon appetito !", badge: null }
    ]
