    ingredients: {},
    etapes: [
      { icone: "🍗", titre: "Cuire la volaille", detail: "Dans un faitout : 1 poulet entier coupé en morceaux + 3 oignons émincés + 4 gousses d'ail + 1 cs ras-el-hanout + 1 cc cannelle + 1 cc gingembre + 1 cc curcuma + safran + sel/poivre + 50g beurre + 200ml d'eau. Mijoter 1h à feu doux. ASTUCE CHEF : version royale = pigeon ou caille au lieu de poulet.", badge: "⏱ 1h" },
      { icone: "🍗", titre: "Effilocher", detail: "Quand le poulet est cuit (la viande se détache des os), retirer. EFFILOCHER finement avec 2 fourchettes. Réserver dans un bol. JETER la peau et les os.", badge: "⏱ 10 min" },
      { icone: "🔥", titre: "Réduire la sauce", detail: "Remettre la cocotte sur le feu sans la viande. Faire RÉDUIRE la sauce à découvert jusqu'à ce qu'il reste 3-4 cs (presque sèche). C'est le secret de la garniture qui ne mouille pas la brick.", badge: "⏱ 15 min" },
      { icone: "🥚", titre: "Œufs brouillés", detail: "Battre 6 œufs avec sel. Verser dans la sauce réduite hors du feu. Remettre sur feu doux et brouiller comme des œufs brouillés. Mélanger avec la viande effilochée.", badge: "⏱ 5 min" },
      { icone: "🌰", titre: "Amandes torréfiées", detail: "Faire dorer 200g d'amandes effilées dans une poêle à sec 5 min jusqu'à BIEN DORÉES. Hacher GROSSIÈREMENT au couteau. Mélanger avec 1 cs de cannelle + 2 cs sucre glace + 1 cc eau de fleur d'oranger.", badge: "⏱ 8 min" },
      { icone: "🌿", titre: "Aromates", detail: "Hacher : grosse poignée de persil + petite poignée de coriandre. Mélanger à la viande aux œufs.", badge: "⏱ 3 min" },
      { icone: "🧈", titre: "Beurrer les bricks", detail: "Faire fondre 100g de beurre. Au pinceau : badigeonner GÉNÉREUSEMENT chaque feuille de brick (12 feuilles environ). Important : feuilles humides du beurre = ne casseront pas.", badge: "⏱ 5 min" },
      { icone: "🏗️", titre: "Montage SPIRALE", detail: "TECHNIQUE TRADITIONNELLE : moule à manqué de 26cm beurré. Disposer 6 feuilles de brick en ÉTOILE qui dépassent largement (50% dehors). Au centre : couche de viande aux œufs, puis couche de mélange aux amandes. Recouvrir de 2 feuilles de brick beurrées au centre. Refermer les feuilles qui dépassent vers le centre, en pliant en pétales.", badge: "⏱ 15 min" },
      { icone: "🧈", titre: "Beurrer le dessus", detail: "Badigeonner LARGEMENT le dessus de beurre fondu. Saupoudrer LÉGÈREMENT de sucre glace.", badge: "⏱ 3 min" },
      { icone: "🔥", titre: "Cuisson", detail: "Cuire à 200°C chaleur tournante 25-30 min. La pastilla doit être DORÉE PROFOND et CROUSTILLANTE. Surveiller la dernière 5 min.", badge: "⏱ 30 min" },
      { icone: "✨", titre: "Décor signature", detail: "Démouler délicatement sur un plat de service. Saupoudrer GÉNÉREUSEMENT de sucre glace. Dessiner des LIGNES de cannelle moulue en quadrillage ou rayons. C'est l'art de la pastilla.", badge: "⏱ 3 min" },
      { icone: "🍽️", titre: "Service marocain", detail: "Servir CHAUD ou tiède (jamais froid). À découper en parts comme une tarte. Accompagner d'un thé à la menthe BIEN SUCRÉ. Tradition royale. Bismillah !", badge: null }
    ]
